"""
MKT Christ Commentary — Exodus chapters 1–3
Run: python3 scripts/zc-christ-exodus-1-3-fill.py

Source data used:
- data/interlinear/exodus.json
- data/translation/draft/mediating/exodus.json

Key decisions in this range:
- Moses is consistently treated as a type of Christ (Deut 18:15-19; Acts 7:20-44; Heb 3:1-6) — not a forced comparison but one the NT explicitly makes
- The Pharaoh/death decree :: Herod/massacre parallel is explicit in Matt 2:16-18 (Jer 31:15 citation)
- Ex 3:6 (I am the God of Abraham) is directly cited by Jesus in Matt 22:32 / Mark 12:26 for resurrection
- Ex 3:14 (Ehyeh asher ehyeh) is the basis for John's ego eimi statements (John 8:58, 6:35, 10:11, etc.)
- Ex 3:8 (I have come down to deliver) is echoed verbatim in John 6:38 (I have come down from heaven)
- Revelation of God entries are used for verses where the divine character revealed anticipates its full expression in Christ
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS = {
"1": {
"1": "<p>The theme of covenant continuity: the names of Jacob's sons carried into Egypt are the seed of the nation that will be constituted at Sinai. Matthew's genealogy (1:1-17) opens with the same narrative logic — names carried forward through darkness and exile, preserving the covenant line. The people of God exist before their deliverer; the deliverer is sent to a community already formed by divine promise.</p>",
"2": "<p>The twelve sons of Jacob descend into Egypt; Jesus appoints twelve apostles to reconstitute Israel around himself (Matt 10:1-4; 19:28). The number twelve is not incidental — it signals the reconstitution of all twelve tribes in the new covenant community. As the sons of Jacob were the seed of the nation, the twelve apostles are the foundation of the new Israel (Eph 2:20; Rev 21:14).</p>",
"3": "<p>Issachar and Zebulun — two of the tribes whose inheritance in Canaan will be in Galilee, the northern region. Matt 4:13-16 quotes Isa 9:1-2: 'Land of Zebulun, land of Naphtali... the people living in darkness have seen a great light.' Jesus begins his ministry precisely in the territory of these two sons, fulfilling a prophecy rooted in this very tribal geography.</p>",
"4": "<p>Benjamin, Dan, Naphtali, Gad, Asher — the sons of the concubines complete the twelve. The inclusion of sons from all four mothers in the covenant community anticipates the gathering of people from all nations into Christ (Gal 3:28: 'There is neither Jew nor Gentile... you are all one in Christ Jesus'). The covenant community was always broader than a single bloodline.</p>",
"5": "<p>Seventy persons descend into Egypt. Jesus sends out seventy-two (some manuscripts: seventy) disciples in Luke 10:1-24, paralleling the earlier mission of the twelve. As the seventy descendants of Jacob entered the land of bondage bearing the covenant promise, the seventy sent by Jesus enter towns bearing the kingdom of God. The correspondence between the two missions (and the joy of the commissioned on their return) reflects the same divine-commission pattern.</p>",
"6": "<p>Joseph and all his brothers and that generation died — the mediating generation passes from the scene. The removal of the familiar mediator is the structural precondition for the suffering that calls forth the new, greater deliverer. Theologically: the covenant promise outlives every human mediator. Christ is the one mediator who does not die and leave the community exposed — he lives forever to intercede (Heb 7:25).</p>",
"7": "<p>Israel's multiplication in the land of affliction — the more the people were afflicted, the more they grew (v.12). The theme of life through death, growth through opposition, multiplication through persecution runs through redemptive history: the early church multiplied precisely as it was scattered under persecution (Acts 8:1-4). Jesus frames it as seed-logic: unless a grain of wheat falls into the earth and dies, it remains alone; if it dies, it bears much fruit (John 12:24). The covenant community cannot be suppressed by earthly power.</p>",
"8": "<p>A new king who did not know Joseph — the rejection of the mediator, and the consequent persecution of those he protected. The pattern recurs in John 1:11: 'He came to his own, and his own did not receive him.' The world that benefited from Joseph's provision and Moses' liberation ultimately does not acknowledge the source of its blessing. The rejection of the mediator by the ruling power — Pharaoh ignoring Joseph, Pilate condemning Jesus — is a structural feature of redemptive history.</p>",
"9": "<p>Pharaoh fears the covenant community — 'more numerous and stronger than we.' The earthly power perceives the people of God as a threat precisely because divine blessing cannot be contained within the world's categories of control. Revelation 12-13 depicts the same dynamic eschatologically: the dragon pursues the woman and her offspring because he cannot absorb or destroy what God is doing. The covenant people are always, in some sense, a threat to the kingdoms of this world.</p>",
"10": "<p>Pharaoh's shrewdness deployed against the covenant people — the wisdom of this age confronting the divine purpose. Paul reflects on this pattern in 1 Cor 2:6-8: the rulers of this age did not understand the wisdom of God; if they had, they would not have crucified the Lord of glory. The very instrument by which the earthly powers tried to eliminate the threat (crucifixion) became the means of their defeat. Pharaoh's shrewd plan to stop Israel produced the exact outcome he feared; Pilate's verdict accomplished the exact purpose he sought to prevent.</p>",
"11": "<p>Israel labors to build Egypt's store cities — the covenant people's labor under the world's authority. A shadow: the Servant of Isaiah 52-53 is 'despised and rejected,' 'oppressed and afflicted,' bearing burdens not his own. Jesus identifies himself with the laboring and heavy-laden (Matt 11:28) precisely because the Son of God entered the condition of servitude to liberate those under it. The one who called Israel out of Egypt's service calls those under sin's burden to himself.</p>",
"12": "<p>The more they were afflicted, the more they multiplied — the paradox of the indestructible covenant community. This principle governs the entire NT mission: persecution spreads the gospel (Acts 8:4); suffering produces endurance (Rom 5:3-4); death produces life (John 12:24). The blood of the martyrs is the seed of the church (Tertullian). Pharaoh's attempt to reduce Israel produces the numerical growth that makes his fear self-fulfilling — exactly as the authorities' attempt to suppress the early church produced its expansion.</p>",
"13": "<p>Crushing labor (<em>abodah parach</em>) — the same term later forbidden in Israel's own slave law (Lev 25:43). A shadow: the Servant of Isaiah 53:4-5 carries grief and sorrows, is stricken and crushed (<em>medakka</em>) — the same crushing that characterizes Egypt's oppression is the suffering the Servant takes on for others. Christ takes on the crushing that Israel suffered from Egypt, and the crushing that all humanity suffers under sin, bearing it in himself.</p>",
"14": "<p>Bitter labor in mortar and brick and all field service — the bitterness of Egypt, memorialized in the bitter herbs of the Passover feast. At Gethsemane, Jesus asks if the cup of bitterness can pass from him (Matt 26:39) — the cup that Israel drank under Pharaoh becomes the cup the Servant drinks on behalf of all. The word Gethsemane means 'olive press' — the place of crushing. The bitterness of Egypt's service is contained within the bitterness of Gethsemane's prayer.</p>",
"15": "<p>The midwives receive the death decree against Hebrew boys — the first of two death decrees in the Exodus narrative (the second in v.22 extends to all Egypt). A type: the decree to kill male infants at birth is the exact form of Herod's response to news of the Messiah's birth in Bethlehem (Matt 2:16). Matthew quotes Jer 31:15 ('Rachel weeping for her children') to link the two events explicitly — the slaughter at Bethlehem is the Exodus pattern repeated in the fullness of time.</p>",
"16": "<p>A type: the death decree against Hebrew boys by the earthly king parallels Herod's massacre of the innocents (Matt 2:16-18) with structural precision: a powerful ruler fears the coming deliverer, issues a death decree against male infants, and the deliverer escapes while others die. Matthew explicitly connects the two events by citing Jer 31:15. The decree intended to prevent the deliverer's emergence is the backdrop against which the deliverer's miraculous preservation is displayed.</p>",
"17": "<p>The midwives feared God rather than the king — the first act of obedience to divine authority over human authority in redemptive history. The NT principle stated in Acts 5:29 ('We must obey God rather than human beings') has its founding moment here. The midwives who protected the infant Israelites under a death decree are the counterparts of those who protect and serve Jesus despite hostile authority — Joseph, who hid the family in Egypt; the magi, who did not report to Herod (Matt 2:12).</p>",
"18": "<p>Pharaoh interrogates the midwives about their disobedience — the covenant community called to account before earthly power for protecting what God is doing. Theme: the pattern recurs throughout the NT (Acts 4:7: 'By what power or what name did you do this?'). Those who stand before authority to answer for faithfulness to God participate in the same witness the midwives gave — calm, truthful, unafraid.</p>",
"19": "<p>The midwives' reply — the Hebrew women are vigorous and give birth before they arrive. Theme: the life-force of the covenant community outpaces the reach of the death decree. The resurrection is the ultimate statement of this theme: the death decree of sin and law (Rom 6:23) is outrun by the life of God in Christ. Death cannot keep what Christ has made alive (Acts 2:24: 'it was impossible for death to keep its hold on him').</p>",
"20": "<p>God was kind to the midwives and the people multiplied — divine blessing on faithful disobedience to a death decree. A revelation of God: YHWH rewards those who protect the vulnerable and honor him above earthly power. This divine character — rewarding those who align with God's purposes over against earthly authority — is fully expressed in Christ's beatitudes (Matt 5:3-12: blessed are those who are persecuted for righteousness).</p>",
"21": "<p>God gave the midwives families of their own — life for those who gave life. The principle of seed and harvest (Gal 6:7-8) is illustrated in this reward: the midwives preserved the lives of Hebrew children; God gives them children. The theme of resurrection-reward — receiving back what was risked for God's sake — runs through the NT (Mark 10:29-30: 'no one who has left... for me and the gospel will fail to receive a hundred times as much').</p>",
"22": "<p>A type: Pharaoh's edict to throw every Hebrew boy into the Nile directly parallels Herod's massacre of the innocents (Matt 2:16-18). The NT does not make the connection allegorically — Matthew does it textually, citing Jer 31:15 to show that both events are part of the same redemptive pattern. In both, an earthly king fears the deliverer and acts with mass violence; in both, the deliverer is preserved while the innocent die. The preserved deliverer carries the weight of the innocent who died for his sake.</p>"
},
"2": {
"1": "<p>A Levite man marries a Levite woman — the deliverer will come from the priestly tribe. The NT notes that Jesus belongs to the royal tribe (Judah/David) through Joseph, but Luke 1:36 identifies Elizabeth (mother of John the Baptist) as a daughter of Aaron, and Elizabeth and Mary are relatives — meaning Jesus has both royal and priestly lineage in his extended family. The priestly and royal vocations that were constitutionally separate in the Mosaic order converge in Christ (Heb 7:14-16).</p>",
"2": "<p>She saw that he was good (<em>ki tov</em>) — the creation goodness formula (Gen 1:4, 10, 12, etc.) applied to the child. A shadow: the Incarnation is the arrival of the one who is the image of God (2 Cor 4:4; Col 1:15) — the one in whom the goodness of creation is fully expressed and from whom it flows. Joseph and Mary hide the child from Herod for two years (Matt 2:13-15) just as the mother hides Moses for three months — the preservation of the deliverer by those who recognize his significance.</p>",
"3": "<p>The tevah (basket/ark) placed in the Nile waters — a type with two layers. First, the tevah (used only here and in Gen 6-9 for Noah's ark) signals that Moses is a new Noah: preserved in a vessel on threatening waters while death surrounds. Second, the infant placed in the waters who emerges as deliverer anticipates the Baptism pattern — Jesus enters the Jordan's waters (Matt 3:13-17), is identified as God's Son, and emerges to lead his people through the wilderness. Both Noah's ark and the baptismal waters accomplish preservation through death-threatening water.</p>",
"4": "<p>Miriam watches from a distance — the faithful witness at the water, positioned at the margin of events. A shadow: women watch Jesus from a distance at the cross (Matt 27:55-56), and women are the first witnesses at the empty tomb (Matt 28:1-10). The marginal witness — female, young, powerless — is consistently the first and most faithful observer of the deliverer's vulnerability and triumph throughout redemptive history.</p>",
"5": "<p>Pharaoh's daughter descends to the Nile to bathe and discovers the basket — providence arranges the meeting of the condemned child with the one who has power to save him. A revelation of God: YHWH uses the unexpected, the Gentile, the powerful-for-worldly-purposes to accomplish his purpose. The Magi (Gentile astronomers) come to honor Jesus; the Roman centurion confesses him at the cross (Matt 27:54). Those outside the covenant people often recognize and protect the deliverer.</p>",
"6": "<p>She had compassion on him — <em>vatachmol</em>, from the same root as <em>racham</em> (womb-love, compassion). A revelation of God: the character of divine compassion that moves YHWH to deliver Israel (Ex 3:7: 'I know their sufferings') is expressed through a human being who sees, recognizes, and has compassion on a condemned child. Jesus is consistently described as moved with compassion (<em>esplagchnisthe</em> — Matt 9:36, 14:14, 15:32, 20:34), seeing what others pass by. The compassion of Pharaoh's daughter is a creaturely reflection of the divine compassion that became incarnate in Christ.</p>",
"7": "<p>Miriam's initiative — arranging for Moses' own mother to nurse him at Pharaoh's expense. A shadow: the providential reversal of the death decree through human initiative and divine orchestration. The Incarnation is the ultimate such reversal: what the powers of this world intended as defeat (the cross) becomes the means of cosmic victory. The deliverer is preserved and nourished by the very household that sought his death.</p>",
"8": "<p>Pharaoh's daughter accepts Miriam's offer — the authority that condemned now sponsors. A shadow: the Roman court that condemned Jesus (crucifixion under Pontius Pilate, a Roman legal execution) has its verdict reversed when a Roman soldier confesses him as the Son of God (Matt 27:54) and the empire eventually adopts the faith. The household of the oppressor becomes the context in which the deliverer is formed — Joseph's imprisonment by Potiphar becomes his path to Pharaoh's court; Jesus' death under Roman authority becomes the basis of the Roman church.</p>",
"9": "<p>'Take this child and nurse him for me, and I will give you your wages' — the mother of the condemned child is paid by the household of condemnation to raise her son. A revelation of God: divine irony as the mode of grace. What the world intends as final becomes the condition of formation. The wisdom of God is foolishness to the world (1 Cor 1:25); the power of God is displayed in what appears weak. Jochebed, paid by Pharaoh's court to nurse the future liberator of Israel, embodies this principle at the personal level.</p>",
"10": "<p>Moses is raised in the Egyptian palace — forty years of formation in the household of the oppressor. Acts 7:22 adds: 'Moses was educated in all the wisdom of the Egyptians and was powerful in speech and action.' A shadow: Jesus grows up hidden in Nazareth, his messianic identity concealed while he is formed through ordinary human life, labor, and learning (Luke 2:52: he grew in wisdom and stature). The deliverer's public identity is preceded by decades of hidden formation that the world neither sees nor values.</p>",
"11": "<p>Moses goes out to see his brothers' suffering and identifies with them — the moment of identification. A type: the Incarnation is this moment raised to cosmic scale. John 1:14: 'The Word became flesh and dwelt among us.' Jesus goes out to where his people are, takes on their condition (Phil 2:6-8: 'being found in human form, he humbled himself'). Moses identifies with the Hebrews by going where they are; the eternal Son identifies with humanity by becoming what we are.</p>",
"12": "<p>Moses kills the Egyptian and hides him in the sand — the failed first rescue, the unauthorized act of justice. A shadow of the contrast with Christ: Moses acts without commission, in secret, and the result is flight rather than liberation. Jesus acts with full divine authorization, openly, and the result is completed redemption. Moses' failed attempt highlights what is distinctive about Christ's: not impulsive but sent; not hidden but public; not partial but complete (Heb 3:3-6: Jesus worthy of more glory than Moses).</p>",
"13": "<p>Moses is rejected by a Hebrew who asks 'Who made you a ruler and judge over us?' — a direct citation by Stephen in Acts 7:27, 35 as the pattern repeated with Jesus. Stephen explicitly argues: this is how Israel treats its sent deliverers. The one raised up by God to rescue them is first rejected by the very people he was sent to save; only after rejection, suffering, and divine vindication is he recognized as the appointed deliverer. Stephen uses this argument to explain the crucifixion: Israel rejected Jesus as they rejected Moses at first.</p>",
"14": "<p>A type, explicitly drawn in Acts 7:27, 35: 'Who made you ruler and judge?' — the rejection of the sent deliverer by those he was sent to save. Stephen's argument in Acts 7:25-27 is that Moses is the prototype of the rejected and then vindicated deliverer: 'He assumed that his own people would understand that God was using him to rescue them, but they did not.' The NT uses this rejection-then-vindication pattern as the interpretive framework for the crucifixion and resurrection of Jesus.</p>",
"15": "<p>Moses flees to Midian and spends forty years as a shepherd in the wilderness. A shadow: the forty years in Midian correspond structurally to Jesus' forty days in the wilderness (Matt 4:1-11). Both involve withdrawal, testing, and formation before the public commissioning that inaugurates the mission of deliverance. Both figures emerge from the wilderness experience to confront the powers of their day. The wilderness is the school of the deliverer — the place where human resources are stripped away and divine provision is the only ground to stand on.</p>",
"16": "<p>Moses meets the seven daughters of Jethro at the well in Midian — the shepherd who defends the vulnerable at the place of water. A shadow: Jesus meets the Samaritan woman at Jacob's well (John 4:6-26), offering living water and identifying himself as the promised Messiah. The well-meeting scene is a patriarchal type-scene (Isaac/Rebekah, Jacob/Rachel) that culminates in Jesus' conversation at the well — the Good Shepherd (John 10:11) meets the excluded at the water.</p>",
"17": "<p>Moses drives away the male shepherds and waters the flock for Jethro's daughters — the shepherd protects the vulnerable against exploitation. A type: Jesus drives out those who exploit the temple (Matt 21:12-13), cleansing the place of divine encounter from commercial predation. The Good Shepherd protects the sheep from the hireling who abandons them (John 10:11-13). Moses' protective act at the Midianite well is a miniature of the Good Shepherd's defining character.</p>",
"18": "<p>Jethro's daughters report 'an Egyptian man delivered us' — the deliverer's identity is hidden behind his appearance. Moses looks Egyptian; he is Hebrew. A shadow: Jesus is identified as a Galilean carpenter (Mark 6:3), his divine identity hidden behind human appearance. Those who receive him are those who look past the apparent and recognize the real (Matt 16:16-17: Peter's confession — 'You are the Messiah' — revealed by the Father, not by flesh and blood).</p>",
"19": "<p>The deliverer rescues the daughters from hostile shepherds and provides water for their flock. A revelation of God: the same divine character that acts on behalf of the powerless against the powerful — the theme of Ex 3:7-10 — is expressed in Moses' act at the well. The God who hears the cry of the oppressed in Egypt acts through Moses at a Midianite well. Jesus' ministry is the Incarnation of this divine disposition: he heals on the Sabbath, eats with sinners, touches lepers — the God who sides with the vulnerable, present in human form.</p>",
"20": "<p>Jethro's hospitality invitation — the priest of Midian recognizes the deliverer and brings him in. A shadow: Cornelius (Acts 10), the Roman centurion who receives the gospel first among the Gentiles, mirrors Jethro — a non-Israelite who receives the sent one with hospitality and whose household becomes the first Gentile church. The trajectory of the gospel — from Israel to the nations — is anticipated in Moses' sojourn in Midian and his reception into a Gentile priestly household.</p>",
"21": "<p>Moses marries Zipporah — the deliverer takes a bride from among the nations. A theme: Christ takes a bride from among all nations — the church as the bride of Christ (Eph 5:25-27; Rev 19:7-9). As Moses received Zipporah (a Midianite/Gentile) as his bride after fleeing Egypt, so Christ's bride is drawn from all peoples, languages, and nations (Rev 5:9-10). The Gentile bride of the covenant mediator is a recurring type: Rahab, Ruth, Bathsheba in Matthew's genealogy (1:5-6), and Zipporah here.</p>",
"22": "<p>'I have been a stranger in a foreign land' — Gershom. The deliverer lives as an alien, belonging fully to no earthly nation. A shadow: 'The Son of Man has nowhere to lay his head' (Matt 8:20). Jesus is the ultimate Gershom — the stranger in the world he made (John 1:10-11: 'the world did not recognize him... his own did not receive him'). The deliverer's estrangement from every earthly home is the condition that enables him to be the home of all who have no home.</p>",
"23": "<p>The Israelites groan and cry out — the legal appeal (<em>za'aqah</em>) reaching the divine throne. A revelation of God that culminates in Christ: the God who hears the cry of the oppressed is the God who in Christ identifies himself as the one to whom the weary and heavy-laden should cry (Matt 11:28). Jesus himself cries out from the cross ('Eloi, Eloi, lama sabachthani' — Mark 15:34), entering the position of the abandoned crier and transforming it from the inside. The God who hears the cry of Ex 2:23 becomes in Christ the one who cries it.</p>",
"24": "<p>God remembered his covenant with Abraham, Isaac, and Jacob — the covenant-memory as the engine of redemption. A direct theological foundation: Paul argues in Gal 3:15-18 and Rom 4 that God's covenant with Abraham, confirmed 430 years before the law, is the ground of salvation — and this is the covenant YHWH remembers here. What God remembers in Ex 2:24 he fulfills in Christ: 'all the promises of God find their Yes in him' (2 Cor 1:20). The Exodus is the first installment of a redemption that finds its final expression in the cross and resurrection.</p>",
"25": "<p>God saw Israel and was concerned — four acts of divine attention (heard, remembered, saw, knew) constitute the prelude to divine action. A revelation of God that culminates in the Incarnation: the God who sees, hears, remembers, and knows the condition of his people does not remain at a distance. In Christ, divine attention becomes divine presence: 'the Word became flesh and dwelt among us' (John 1:14) — the God of Ex 2:25 comes himself to be with those whose condition he knows. The four verbs of attention become the one act of permanent arrival.</p>"
},
"3": {
"1": "<p>Moses in the far wilderness — the future deliverer tending another man's flock in obscurity. A shadow: Jesus spent thirty years in Nazareth in carpenter's work before his public commissioning. The deliverer's public ministry is preceded by obscure, patient labor. Deut 18:15's promise of a prophet like Moses — the promise grounding the entire OT prophetic tradition — is fulfilled by the one who began, like Moses, in an unrecognized shepherding work before the divine commission came.</p>",
"2": "<p>The burning bush — fire that burns without consuming, the theophany at the mountain. A shadow and type: the Transfiguration (Matt 17:1-8) is the NT burning bush — the divine glory blazing through Jesus' human form, the fire of deity burning in the bush of flesh without consuming it. In both events, the disciples/Moses are terrified and fall on their faces; in both, a divine voice commissions the witness. The bush that burns but is not consumed is the visual form of the Incarnation: the eternal fire of divine holiness dwelling in mortal flesh without destroying it.</p>",
"3": "<p>Moses turns aside to investigate — the curiosity that opens into commissioning. A revelation of God: the divine approach is gentle, inviting investigation rather than commanding from a distance. Jesus invites approach in exactly the same way: 'Come to me' (Matt 11:28), 'Follow me' (Mark 1:17), 'Come and see' (John 1:39). The burning bush does not blast Moses from afar; it draws him near and waits. The divine initiative that invites rather than coerces is the form of grace throughout Scripture.</p>",
"4": "<p>'Moses, Moses' — the double personal naming, the form of divine call. Throughout the NT, Jesus calls individuals by name: 'Mary' (John 20:16 — the resurrection encounter), 'Saul, Saul' (Acts 9:4 — the Damascus road), 'Simon, Simon' (Luke 22:31 — the warning). The double calling in the OT (Abraham, Abraham in Gen 22:11; Samuel, Samuel in 1 Sam 3:10) signals sovereign attention and urgent commission. 'Here I am' (<em>hineni</em>) — the response of total availability: the form of election is always this exchange of divine address and human response.</p>",
"5": "<p>'Remove your sandals — the place where you stand is holy ground.' In John 1:27, John the Baptist declares he is not worthy to remove the sandal of the one coming after him. The command at the burning bush reverses: Moses removes his sandals before the presence of YHWH; John refuses to remove the sandal of Jesus because Jesus' presence far exceeds the category that requires sandal-removal. The one before whom Moses removes his sandals is the one before whom John cannot presume to act as a slave.</p>",
"6": "<p>A direct Christological argument: Jesus cites this verse in Matt 22:32 / Mark 12:26 to prove the resurrection of the dead. His logic: YHWH says 'I am the God of Abraham' (present tense) — therefore Abraham is alive before God at the moment Moses stands at the bush. YHWH is not God of the dead but of the living. The burning bush is therefore not merely the site of Moses' commission but the scriptural proof, in Jesus' own teaching, that death does not end the relationship between YHWH and his covenant people.</p>",
"7": "<p>'I have surely seen... I have heard... I know their sufferings' — the threefold divine attention. A revelation of God: the compassionate, responsive God who sees and knows the suffering of his people is the God who becomes incarnate precisely to share and bear that suffering. Isa 53:3-4: the Servant is 'a man of suffering, and familiar with pain... he took up our pain and bore our suffering.' The God of Ex 3:7 does not merely see from above; in Christ he descends into the suffering he sees. The Incarnation is the fullest form of YHWH's 'I know their sufferings.'</p>",
"8": "<p>A near-direct citation: 'I have come down to deliver them and to bring them up out of that land.' Jesus says in John 6:38: 'For I have come down from heaven, not to do my own will but the will of him who sent me.' The vocabulary is the same: divine descent, purposive delivery, bringing up and out. John's entire prologue (1:1-18) is structured around the pattern announced in Ex 3:8: the descent of the divine to deliver and bring up. The Exodus is not merely a historical parallel — it is the conceptual template for the Incarnation.</p>",
"9": "<p>The cry of the Israelites has reached YHWH and he has seen their oppression — the legal appeal received and acknowledged. A revelation of God: the God who attends to the cry of the powerless is the God whose Son responds to every cry of need in the gospels. Blind Bartimaeus calls out and is not silenced (Mark 10:46-52); the ten lepers cry from a distance (Luke 17:11-13); Jairus falls at Jesus' feet (Mark 5:22-23). The God who heard the cry of enslaved Israel hears every human cry through the one in whom he became fully human.</p>",
"10": "<p>'Come, I will send you to Pharaoh' — the commissioning of Moses as shaliach (sent one). A type: Jesus is consistently identified as the one sent by the Father (John 3:17, 5:24, 6:38-40, 17:3). The chain of sending runs from Ex 3:10 through the apostolate: 'As the Father has sent me, I am sending you' (John 20:21). Deut 18:15 promises that YHWH will raise up a prophet like Moses — one who speaks YHWH's words as his commissioned representative, the ultimate sent one whose words are the Father's own (John 14:10).</p>",
"11": "<p>'Who am I?' — Moses' objection based on inadequacy. A revelation of God by contrast: Jesus never asks 'who am I?' His identity is given, not sought (Matt 3:17: 'This is my Son, whom I love'). Moses points forward to the one whose commission requires no qualification — not 'who am I to go?' but 'I and the Father are one' (John 10:30). Heb 3:1-6 makes the comparison explicit: Moses was faithful in God's house as a servant; Jesus is faithful as the Son over the house. The servant's inadequacy points to the Son's sufficiency.</p>",
"12": "<p>The sign that comes after, not before — faith required before evidence arrives. A shadow: the structure of all Christian discipleship mirrors this pattern. Jesus calls the disciples to follow before they fully understand (Mark 1:17-20); the resurrection is the retrospective sign that confirms the mission, not the advance proof that enables it. Heb 11:27 (Moses) and the whole gallery of faith in Heb 11 are structured around this pattern: acting on the unseen promise, receiving the confirmation after. The burning bush sign is the template of faith.</p>",
"13": "<p>Moses asks what name to give when Israel asks who sent him — the demand for divine identification. The question anticipates the NT's central dispute about Jesus' identity. 'Who are you?' is asked of Jesus repeatedly (John 8:25, Mark 11:28). His answer, grounded in the divine name revealed here, is the claim that divides: 'I am' (John 8:58). The question of Ex 3:13 — by whose authority and in whose name? — is the question the religious authorities ask of Jesus at every turn (Mark 11:28: 'By what authority are you doing these things?').</p>",
"14": "<p>A direct and foundational Christological text: 'I AM WHO I AM' (<em>Ehyeh asher ehyeh</em>) — the divine name revealed to Moses at the burning bush. Jesus applies the absolute 'I am' (<em>ego eimi</em>) to himself in John 8:58: 'Before Abraham was, I am' — the crowd recognizes the claim and takes up stones (John 8:59). The seven 'I am' statements in John (bread of life, light of the world, gate, good shepherd, resurrection and life, way/truth/life, true vine) are elaborations of what the name means concretely. The divine name of Ex 3:14 is the name Jesus claims as his own throughout John's Gospel.</p>",
"15": "<p>YHWH as the covenant name, the name that is memorial throughout all generations — a direct connection to the NT's treatment of the name of Jesus. Phil 2:9-11: God gave him 'the name that is above every name, so that at the name of Jesus every knee should bow.' Acts 4:12: 'there is no other name under heaven given to mankind by which we must be saved.' The name YHWH that was Israel's exclusive covenant memorial (Ex 3:15) is, in the NT's understanding, borne by Jesus — the one in whom YHWH's character and covenant are fully disclosed and embodied.</p>",
"16": "<p>Gather the elders of Israel — Moses convenes Israel's representative leadership before his mission begins. A type: Jesus gathers the twelve apostles as the representative reconstitution of Israel's twelve tribes (Matt 19:28). The assembly of the elders in Ex 3:16 is the OT counterpart of the calling of the twelve: in both cases, the deliverer's first act is to constitute a representative body through whom the covenant community will be organized and the mission carried out.</p>",
"17": "<p>The land of milk and honey — the inheritance promised to Abraham and now being actualized. A shadow: the promised land is a type of the ultimate inheritance of the people of God. Heb 11:13-16 makes this explicit — the patriarchs welcomed the promises from afar and acknowledged they were strangers on the earth, looking forward to a better country, the heavenly one. 1 Pet 1:4 describes the Christian inheritance as 'imperishable, undefiled, and unfading, reserved in heaven for you' — what Canaan was typologically, the new creation is permanently. Jesus comes to give his people not a land but himself as their dwelling (John 14:2-3).</p>",
"18": "<p>'Let us go a three-day journey to sacrifice to YHWH our God' — the three-day journey for sacrifice. A shadow: the three-day pattern in the OT is consistently connected to deliverance and resurrection (Gen 22:4 — Abraham sees the mountain on the third day; Jonah 1:17 — three days in the fish; Hos 6:2 — on the third day he will restore us). Jesus applies the Jonah sign explicitly to his own death and resurrection (Matt 12:40). The three-day journey to the place of sacrifice in Ex 3:18 is a small shadow of the three days between the cross and the empty tomb.</p>",
"19": "<p>YHWH foreknows that Pharaoh will resist — the hardened heart of the earthly ruler. A revelation of God: YHWH's purposes are not blocked by human resistance; they are accomplished through it. Rom 9:17 applies this directly: 'I raised you up for this very purpose, that I might display my power in you' (citing Ex 9:16). The hardening of Pharaoh's heart demonstrates that the powers of this age cannot finally resist the divine purpose — the same principle Paul applies to the cross: the rulers of this age crucified the Lord of glory, thus unknowingly accomplishing the purpose they sought to prevent (1 Cor 2:8).</p>",
"20": "<p>The wonders YHWH will perform against Egypt — the signs and miracles that authenticate the divine commission and break the power of the oppressor. A theme: Jesus performs signs and wonders that authenticate his messianic commission (John 10:25, 20:30-31). The purpose of both the Exodus signs (demonstrating YHWH's sovereignty over Egypt's gods) and Jesus' signs (demonstrating the kingdom's arrival) is the same: to show that the power of the deliverer exceeds the power of every opposing force. The plagues dethrone Pharaoh; the miracles of Jesus dethrone the power of sin, disease, and death.</p>",
"21": "<p>YHWH will cause the Egyptians to look favorably on Israel — divine reversal of the social order. A revelation of God: the God who reverses social hierarchies in favor of the covenant community. The Magnificat (Luke 1:46-55) is the NT statement of this principle: 'he has scattered those who are proud... he has brought down rulers from their thrones but has lifted up the humble... he has filled the hungry with good things but has sent the rich away empty.' What YHWH does for Israel in Egypt, he does definitively for all humanity in Christ.</p>",
"22": "<p>The plundering of Egypt — Israel leaves with silver, gold, and clothing from their Egyptian neighbors. A shadow: Col 2:15 describes the cross as the plundering of the powers and authorities: 'Having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross.' What Egypt's wealth was to Israel's exodus, the spoils of the cross are to the church's liberation: the very resources of the enemy become the endowment of the delivered people. The exodus that began with a death decree ends with the covenant community enriched at the oppressor's expense.</p>"
}
}

def main():
    data = load_comm('mkt-christ', 'exodus')
    merge_comm(data, EXODUS)
    save_comm('mkt-christ', 'exodus', data)

    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'exodus.json'))
    all_ok = True
    for ch in ['1', '2', '3']:
        il_vv = set(il.get(ch, {}).keys())
        out_vv = set(data.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
